import{_ as t,o as a,c as o,ag as n}from"./chunks/framework.eQLvDOR_.js";const c=JSON.parse('{"title":"Is the IDE dead?","description":"","frontmatter":{"title":"Is the IDE dead?","source":"https://x.com/addyosmani/article/2035444544125456785","clipped_at":"2026-04-05T00:00:00.000Z","category":"AI_IDE_And_CLI","tags":["ide","agent-orchestration","future-of-development"],"status":"distilled","compiled":true},"headers":[],"relativePath":"library/AI_IDE_And_CLI/AI_IDE_And_CLI - Is the IDE dead_.md","filePath":"library/AI_IDE_And_CLI/AI_IDE_And_CLI - Is the IDE dead_.md","lastUpdated":null}'),r={name:"library/AI_IDE_And_CLI/AI_IDE_And_CLI - Is the IDE dead_.md"};function s(i,e,l,h,d,g){return a(),o("div",null,[...e[0]||(e[0]=[n('<p><strong>The</strong> <strong>center</strong> <strong>of developer work is moving.</strong> Not disappearing - moving. Away from continuous, line-by-line editing inside a single window, and <strong>toward supervising agents</strong> that can plan, rewrite files, run tests, and propose changes for review. IDEs as we know them may stop being the primary tool for software work, or heavily evolve.</p><p>Across the tools many developers including myself are already using daily - <a href="https://conductor.build/" target="_blank" rel="noreferrer">Conductor</a>, <a href="https://code.claude.com/docs/en/claude-code-on-the-web" target="_blank" rel="noreferrer">Claude Code Web</a>, <a href="https://github.com/copilot/agents" target="_blank" rel="noreferrer">GitHub Copilot Agent</a>, <a href="http://jules.google/" target="_blank" rel="noreferrer">Jules</a>, <a href="https://www.vibekanban.com/" target="_blank" rel="noreferrer">Vibe KanBan</a>, even cmux - the same shift keeps showing up: <strong>the control plane is becoming the primary surface, and the editor is becoming one of several instruments underneath it.</strong></p><p><img src="https://pbs.twimg.com/media/HD9Ty4absAA4ryt?format=jpg&amp;name=large" alt="Image"></p><p>Cursor just shipped <a href="https://cursor.com/glass" target="_blank" rel="noreferrer">Glass</a> - a new interface explicitly built to make &quot;working with agents clear, intuitive, and in your control&quot; where agent management is the primary experience and the traditional editor is something you reach for when you need to go deeper. The <a href="https://x.com/F2aldi/status/2034801927041818823" target="_blank" rel="noreferrer">reaction</a> from developers was immediate:</p><blockquote><p>Now Cursor feels more like an Agent Orchestrator than an IDE. Managing agents in parallel is easier</p></blockquote><p><img src="https://pbs.twimg.com/media/HD9T2qBbEAAzhrv?format=jpg&amp;name=large" alt="Image"></p><p>But Glass is one data point in a much larger pattern. Terminal UIs like <a href="https://cmux.com/" target="_blank" rel="noreferrer">cmux</a> highlight how the surfaces we&#39;re used to are evolving to better manage agent workflows.</p><p><img src="https://pbs.twimg.com/media/HD9T5zEasAA_d4S?format=png&amp;name=large" alt="Image"></p><h2 id="from-editing-files-to-steering-workstreams" tabindex="-1">From editing files to steering workstreams <a class="header-anchor" href="#from-editing-files-to-steering-workstreams" aria-label="Permalink to &quot;From editing files to steering workstreams&quot;">​</a></h2><p>Historically, IDEs optimized for a tight inner loop: open files → edit → build → debug → repeat. <strong>The &quot;death&quot; argument is that this loop is no longer the dominant unit of productivity once agents can execute most of it autonomously.</strong></p><p>The new loop looks like this: <strong>specify intent → delegate → observe → review diffs → merge</strong>. What makes it different from &quot;autocomplete with a chat window&quot; is tool-using autonomy combined with interfaces designed to make that autonomy governable.</p><p>You can see this playing out across tools already in heavy use. Claude Code Web (or Desktop) and Codex let developers hand off well-defined tasks to agents running in isolated cloud environments, with progress visible in a browser - no terminal, no local setup required.</p><p>GitHub Copilot&#39;s Agents plan and implements multi-file changes independently, creates branches, runs tests, and surfaces a PR for review; the developer&#39;s primary job becomes reviewing the outcome and iterating, not directing each step.</p><p><img src="https://pbs.twimg.com/media/HD9T-FMawAAq11q?format=jpg&amp;name=large" alt="Image"></p><p>Conductor takes a different approach: a desktop app for running multiple Claude Code agents simultaneously in isolated workspaces, with live progress monitoring across all of them. And Google’s Jules handles asynchronous background tasks - you assign work, it runs, you review the result when it&#39;s done.</p><p>What these tools share is a mental model: <strong>the agent is the unit of work, not the file</strong>. The interface worth optimizing is the one that helps you direct, monitor, and review agents - not the one that helps you type faster.</p><h2 id="the-orchestration-layer-taking-shape" tabindex="-1">The orchestration layer taking shape <a class="header-anchor" href="#the-orchestration-layer-taking-shape" aria-label="Permalink to &quot;The orchestration layer taking shape&quot;">​</a></h2><p>The displacement story becomes persuasive only when you look at the specific interface patterns converging across tools.</p><p><img src="https://pbs.twimg.com/media/HD9UBp5bkAAizhb?format=jpg&amp;name=large" alt="Image"></p><p><strong>Work isolation as a primitive.</strong> Parallel agents need to not step on each other. Virtually every serious tool in this space has landed on git worktrees (or similar) as the answer. Conductor maps each agent session to its own isolated workspace. Vibe Kanban (shown above) does the same for its kanban-driven agent workflow. The pattern is near ubiquitous because the problem is real: without isolation, parallel agents produce chaos.</p><p><strong>Planning and task state as the primary UI.</strong> Tools like Vibe Kanban have replaced &quot;tabs and files&quot; with &quot;tasks and states&quot; as the top-level mental model. You create task cards (a landing page, a backend service, an email integration), assign each to an agent and a model, and manage the whole effort like a lightweight project board - except the &quot;team&quot; is running autonomously. This is a project management surface that happens to have agents doing the implementation.</p><p><strong>Background agents and async-first design.</strong> Some of the most interesting tools in this space don&#39;t even try to keep you in the loop during execution. Cursor, Copilot and Antigravity support background agents that run without requiring your presence - you define intent, step away, and review when they&#39;re done. Jules works similarly: assign a task, come back to a diff. The implicit promise is that your attention is too valuable to spend watching a progress bar. That&#39;s a significant departure from the IDE’s real-time, synchronous feedback loop.</p><p><strong>Attention management for parallel agents.</strong> When many agents run concurrently, the real bottleneck becomes knowing which one needs you right now. This is why tools like Conductor surface live progress across sessions and cmux introduced notification rings and unread badges for terminal panes. &quot;Agent needs attention&quot; is becoming a first-class event in the developer environment - something to route and triage, not just notice.</p><p><strong>Agents embedded into the software lifecycle.</strong> GitHub&#39;s Copilot coding agent is asynchronous, secured by a control layer, and powered by GitHub Actions - attached to how code actually ships (issues → PRs → CI → merge), not just how it gets written.</p><p>None of these tools claim IDEs are obsolete - many still interoperate with them. But the repeated patterns (parallel workspaces, diff-first review, task state, background execution, lifecycle integration) are precisely what &quot;death of the IDE&quot; proponents mean when they talk about a center-of-gravity shift.</p><h2 id="why-developers-still-reach-for-an-ide" tabindex="-1">Why developers still reach for an IDE <a class="header-anchor" href="#why-developers-still-reach-for-an-ide" aria-label="Permalink to &quot;Why developers still reach for an IDE&quot;">​</a></h2><p><strong>The best critique of &quot;the IDE is dead&quot; is that the IDE</strong> <strong>still</strong> <strong>compresses several genuinely hard problems into a high-fidelity feedback loop</strong>: precise navigation, local reasoning, interactive debugging, and the ability to understand a system by directly manipulating it.</p><p>Even the most ambitious orchestration tools keep a manual-edit escape hatch. For example, reviewing diffs in-thread, commenting on changes, and then opening the result in your editor for manual adjustments. That&#39;s an acknowledgment that human intervention is part of the intended workflow.</p><p>Agent tooling itself highlights where the limits still are. Multi-file refactorings in large repositories remain among the toughest challenges for software engineering agents. These are exactly the situations where interactive code navigation and human judgment still matter most - where you need to hold a mental model of the system that the agent can&#39;t fully reconstruct from context alone.</p><p>The failure mode that keeps developers anchored to IDE-level inspection is agents being almost right. When something is 90% correct and subtly broken, the cost of finding the issue often exceeds what it would have taken to write it yourself. For high-stakes changes, the IDE remains the best instrument for that kind of deep, precise inspection.</p><h2 id="the-new-costs-review-fatigue-and-governance-overhead" tabindex="-1">The new costs: review fatigue and governance overhead <a class="header-anchor" href="#the-new-costs-review-fatigue-and-governance-overhead" aria-label="Permalink to &quot;The new costs: review fatigue and governance overhead&quot;">​</a></h2><p>If development becomes &quot;run many agents in parallel&quot; the workflow inherits problems that look less like text editing and more like distributed systems management - observability, permissions, isolation, and governance.</p><p>Agent workflows invert the labor. Instead of writing, you&#39;re reviewing. That sounds like an improvement until you&#39;re staring at twelve diffs from twelve parallel agents at the end of the day. Review fatigue is real, and it’s one of the reasons the most thoughtful tools in this space focus on attention routing, structured plans, and review-first gates rather than pushing for full autonomy by default.</p><p>The security surface also expands as agents gain access to more tools, repos, and external systems. As agents can browse the web, query databases, write to filesystems, and trigger deploys, what they&#39;re allowed to do becomes as important as what they&#39;re capable of doing.</p><p>On observability and control, IDE-integrated agent modes are already pushing toward explicit tool logs and approval gates. The governance question isn&#39;t optional once agents act asynchronously and touch CI pipelines.</p><h2 id="what-survives-the-ide-the-control-plane-or-both" tabindex="-1">What survives: the IDE, the control plane, or both <a class="header-anchor" href="#what-survives-the-ide-the-control-plane-or-both" aria-label="Permalink to &quot;What survives: the IDE, the control plane, or both&quot;">​</a></h2><p>A clear reading of the landscape is that &quot;death of the IDE&quot; is directionally right about the center of gravity, but wrong as a literal forecast.</p><p>The strongest version of the claim is this: <strong>the IDE stops being the primary workspace and becomes one of several subordinate instruments</strong> - used for targeted inspection, debugging, and final edits - while planning, orchestration, review, and agent management move into dashboards, issue trackers, observability terminals, and cloud control planes.</p><p>The &quot;bigger IDE&quot; framing is equally well-supported. The new &quot;IDE&quot; is a system that provides multi-agent orchestration, isolated workspaces, permissions and audit logs, diff-first review, reliable tool connectivity, and attention routing. <strong>The file editor is still there. It&#39;s just no longer the front door.</strong></p><p>The IDE isn&#39;t dying. It&#39;s being de-centered. The work is moving outward - into orchestration surfaces where humans define intent, delegate to parallel agent runtimes, and spend more time supervising, reviewing, and governing than typing.</p><p><strong>The IDE remains critical for correctness, comprehension, and the hard problems agents still struggle with. But its no longer the only place where programming happens - and for a growing number, it&#39;s no longer the first place they go.</strong></p>',41)])])}const u=t(r,[["render",s]]);export{c as __pageData,u as default};
